<template>
    <div>
          <loader :isVisible="isLoading"></loader>
          <dynamic-form lang="en" ref="AddlocationRef" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit"></dynamic-form>
      
          <div class="row placeholder">
            <div class="col-md-12 p-0">
                <ReportViewer  v-if="parameter.length>0" :parameter="parameter" :reportPath="reportPath"></ReportViewer>
            </div>
        </div>
      </div>
    </template>
        <script>
        import DataService from '../../services/DataService';
        import ReportViewer from '../HrReport/ReportViewer.vue';
        
        export default {
            components: { ReportViewer },
             data() {
                 return {
                    CompanyReportDDLTypes:[],
                    dtFrom: null,
                    dtTO: null,
                    reportPath: null,
                    parameter: [],
                    DealId:null,
                    mindate:null,
                    FormSchema: [{
                      layoutType: "triple",
                      Data: [
                            {
                                astype: "MultiSelectField",
                                label: this.$t("Deals"),
                                name: "Deals",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t('Deals'),
                                mode: "tag",
                                config: {
                                    options: [],
                                  
                                },
                            },
                              {
                                  astype: "DateField",
                                  label: this.$t("DateFrom"),
                                  name: "dtFrom",
                                  value: "",
                                  placeholder: "10/12/2022 12:AM",
      
                                  config: {
                                      format: "M/D/YYYY"
                                  },
                              },
                              {
                                  astype: "DateField",
                                  label: this.$t("DateTo"),
                                  name: "dtTO",
                                  value: "",
                                  placeholder: "10/12/2022 12:AM",
      
                                  config: {
                                      format: "M/D/YYYY"
                                  },
                              },
                              
                          ],
                  }, ],
                  buttons: [{
                          type: "submit",
                          class: "btn btn-success",
                          text: "<i class='fa fa-search pr-2'></i>Search",
                      },
      
                      {
                          type: "button",
                          class: "btn btn-danger",
                          text: "<i class='fa fa-close pr-2'></i>Clear all",
                          onClick: this.ClearAll
                      },
                  ],
                 }
             },
             created: function () {
            this.GetCompanyReportDDLTypes();
             },
             methods: {
                ClearAll: function () {
            var vm = this;
            (vm.FormSchema)[0].Data[0].value = '';
            (vm.FormSchema)[0].Data[1].value = '';
            (vm.FormSchema)[0].Data[2].value = '';
           
        },
                GetCompanyReportDDLTypes: async function () {
                var vm = this;
                var url = `type=CRM_DEALS&moduleName=CRM`;
                await DataService.GetCompanyReportDDLTypes(url).then((response) => {
                    ;
                    if (response.data.length > 0) {
                        var LocationData = response.data;
                        LocationData.forEach(element => {
                            var Obj = {
                                name: element.name,
                                value: element.value
                            }
                            vm.FormSchema[0].Data[0].config.options.push(Obj);
                        });  
                        vm.$refs.BarcodeReport.UpdateKeyValue();
                    }
                });
            },

            onSubmit: function (e) {
                var reportviewerObj = $("#viewer").data("boldReportViewer");
                if(reportviewerObj != null)
                {
                    reportviewerObj.destroy();
                }
                    var vm = this;
                    vm.isLoading=true;
                    vm.reportPath = '';  
                    vm.parameter=[];
                    var reportModel = {
                        reportName: "dealstagecrmreport",
                        moduleName: "crm",
                        dateFrom: e.dtFrom,
                        dateTo: e.dtTO,
                        dealIds:e.Deals.length > 0 ? e.Deals.map(item => item.value).join(",") : null,
                    };
                    var objectPostString = JSON.stringify(reportModel);
                    DataService.ReportMain(objectPostString).then(response => {
                        vm.reportPath = response.data.ReportPath;
                        vm.parameter = response.data.parameters;
                    });
                    vm.isLoading=false;
                },
                
             }
         }
         
        </script>