<template>
    <div>
          <loader :isVisible="isLoading"></loader>
          <dynamic-form lang="en" ref="BarcodeReport" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit"></dynamic-form>

          <div class="row placeholder">
            <div class="col-md-12 p-0">
                <ReportViewer  v-if="parameter.length>0" :parameter="parameter" :reportPath="reportPath"></ReportViewer>
            </div>
        </div>
      </div>
      </template>
<script>
import DataService from '../../services/DataService';
import ReportViewer from '../HrReport/ReportViewer.vue';
export default {
    components: { ReportViewer },
    data() {
        return {
            statusList:[],
            companyleaderOwner:[],
            companyClientsByCompanyId:[],
            Crmtype:null,
            dtFrom: null,
            dtTo: null,
            reportPath: null,
            parameter: [],
            StatusId:null,
            ClientId:null,
            mindate:null,
            OwnerIds:null,
            leadValueTo:null,
            leadValueFrom:null,
            FormSchema: [{
                    layoutType: "four",
                    Data: [
                        {
                            astype: "MultiSelectField",
                            label: this.$t("Status"),
                            name: "Status",
                            value: "",
                            placeholder: this.$t('Select') + " " + this.$t('Status'),
                            mode: "tag",
                            config: {
                                options: [],
                            },
                        },
                        {
                            astype: "MultiSelectField",
                            label: this.$t("Client Name"),
                            name: "Client",
                            value: "",
                            placeholder: this.$t('Select') + " " + this.$t('Users'),
                            mode: "tag",
                            config: {
                                options: [],
                            },
                        },
                        {
                              astype: "TextField",
                              label: this.$t("Money Value"),
                              name: "leadValueTo",
                              value: "",
                              placeholder: this.$t("From"),
                              config: {},
                        },
                        {
                              astype: "TextField",
                              label: '',
                              name: "leadValueFrom",
                              value: "",
                              placeholder: this.$t("To"),
                              config: {},
                        },

                              {
                                  astype: "DateField",
                                  label: this.$t("DateFrom"),
                                  name: "dtFrom",
                                  value: "",
                                  placeholder: "10/12/2022 12:AM",

                                  config: {
                                      format: "M/D/YYYY"
                                  },
                              },
                              {
                                  astype: "DateField",
                                  label: this.$t("DateTo"),
                                  name: "dtTO",
                                  value: "",
                                  placeholder: "10/12/2022 12:AM",

                                  config: {
                                      format: "M/D/YYYY"
                                  },
                              },
                              {
                            astype: "MultiSelectField",
                            label: this.$t("Lead Owner"),
                            name: "Owner",
                            value: "",
                            placeholder: this.$t('Select') + " " + this.$t('LeadOwner'),
                            mode: "tag",
                            config: {
                                options: [],
                            },
                        },
                    ],


                },


            ],
            buttons: [{
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-search pr-2'></i>Search",
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Clear all",
                    onClick: this.ClearAll
                },
            ],


        };
    },

    created:function()
    {
        var vm=this;
         vm.GetCompanyLeadOwners();
         vm.GetStatusList();
         vm.GetCompanyClientsByCompanyId();

    },
    methods: {

        ClearAll: function () {
            var vm = this;
            (vm.FormSchema)[0].Data[0].value = '';
            (vm.FormSchema)[0].Data[1].value = '';
            (vm.FormSchema)[0].Data[2].value = '';
            (vm.FormSchema)[0].Data[3].value = '';
            (vm.FormSchema)[0].Data[4].value = '';
            (vm.FormSchema)[0].Data[5].value = '';
            (vm.FormSchema)[0].Data[6].value = '';
        },
        GetCompanyLeadOwners: async function () {
                var vm = this;
                var url = `leadId=0&type=P&moduleName=CRM`
                await DataService.GetCompanyLeadOwners(url).then((response) => {
                    ;
                    if (response.data.length > 0) {
                        var LocationData = response.data;
                        LocationData.forEach(element => {
                            var Obj = {
                                name: element.name,
                                value: element.value
                            }
                            vm.FormSchema[0].Data[6].config.options.push(Obj);
                        });  
                        vm.$refs.BarcodeReport.UpdateKeyValue();
                    }
                });
            },

        GetStatusList: async function () {
                var vm = this;
                var url = `langCode=&statusType=CRM&hasglobal=false`
                await DataService.GetStatusList(url).then((response) => {
                    if (response.data.length > 0) {
                        var LocationData = response.data;
                        LocationData.forEach(element => {
                            var Obj = {
                                name: element.STATUS,
                                value: element.STATUS_ID
                            }
                            vm.FormSchema[0].Data[0].config.options.push(Obj);
                        });
                        vm.$refs.BarcodeReport.UpdateKeyValue();
                    }
                });
            },

        GetCompanyClientsByCompanyId: async function () {
                var vm = this;
                await DataService.GetCompanyClientsByCompanyId().then((response) => {
                    if (response.data.length > 0) {
                        var LocationData = response.data;
                        LocationData.forEach(element => {
                            var Obj = {
                                name: element.text,
                                value: element.value
                            }
                            vm.FormSchema[0].Data[1].config.options.push(Obj);
                        });
                        vm.$refs.BarcodeReport.UpdateKeyValue();
                    }
                });
            },
        
        onSubmit: function (e) {
            var reportviewerObj = $("#viewer").data("boldReportViewer");
                if(reportviewerObj != null)
                {
                    reportviewerObj.destroy();
                }
            var vm = this;
            vm.isLoading=true;
            vm.reportPath = '';  
            vm.parameter=[];
            var reportModel = {
                reportName: "crmdetailreport",
                moduleName: "crm",
                dateFrom: e.dtFrom,
                dateTo: e.dtTo,
                StatusIds:e.Status.length > 0 ? e.Status.map(item => item.value).join(",") : '',
                ClientIds:e.Client.length > 0 ? e.Client.map(item => item.value).join(",") : '',
                ownerIds:e.Owner.length > 0 ? e.Owner.map(item => item.value).join(",") : '',
                crmType:"L",
                leadValueFrom:e.leadValueFrom,
                leadValueTo:e.leadValueTo,
            };
            var objectPostString = JSON.stringify(reportModel);
            DataService.ReportMain(objectPostString).then(response => {
                vm.reportPath = response.data.ReportPath;
                vm.parameter = response.data.parameters;
            });
            vm.isLoading=false;
        },
    }
}
</script>